+func clearItermRect(out *bufio.Writer, row, col, cols, rows int) {
+	if out == nil || cols <= 0 || rows <= 0 {
+		return
+	}
+	if row < 1 {
+		row = 1
+	}
+	if col < 1 {
+		col = 1
+	}
+	blank := strings.Repeat(" ", cols)
+	saveCursor(out)
+	for i := 0; i < rows; i++ {
+		moveCursor(out, row+i, col)
+		_, _ = fmt.Fprint(out, blank)
+	}
+	restoreCursor(out)
+}
